import{_ as t,o as e,c as i,ag as l}from"./chunks/framework.C6K0jwmI.js";const b=JSON.parse('{"title":"テイクアウト管理","description":"","frontmatter":{"title":"テイクアウト管理"},"headers":[],"relativePath":"tenant/09-takeout.md","filePath":"tenant/09-takeout.md"}'),r={name:"tenant/09-takeout.md"};function n(o,a,d,s,h,p){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="_9-テイクアウト管理" tabindex="-1">9. テイクアウト管理 <a class="header-anchor" href="#_9-テイクアウト管理" aria-label="Permalink to &quot;9. テイクアウト管理&quot;">​</a></h1><p>テイクアウト管理では、持ち帰り注文の受付、受取時間、オンライン決済、注文ステータスを管理します。</p><h2 id="利用開始前の設定" tabindex="-1">利用開始前の設定 <a class="header-anchor" href="#利用開始前の設定" aria-label="Permalink to &quot;利用開始前の設定&quot;">​</a></h2><ol><li>店舗設定でテイクアウトを有効にします。</li><li>受付時間、受取可能時間、注文上限を設定します。</li><li>テイクアウト対象商品を確認します。</li><li>決済方法を確認します。</li><li>お客様用の案内URLまたはQRコードを掲示します。</li></ol><h2 id="注文受付の流れ" tabindex="-1">注文受付の流れ <a class="header-anchor" href="#注文受付の流れ" aria-label="Permalink to &quot;注文受付の流れ&quot;">​</a></h2><ol><li>お客様がテイクアウトページを開きます。</li><li>商品、数量、受取時間、連絡先を入力します。</li><li>必要に応じて決済を行います。</li><li>店舗側の管理画面に注文が表示されます。</li><li>調理、受け渡し、完了のステータスを更新します。</li></ol><h2 id="営業中の確認ポイント" tabindex="-1">営業中の確認ポイント <a class="header-anchor" href="#営業中の確認ポイント" aria-label="Permalink to &quot;営業中の確認ポイント&quot;">​</a></h2><ul><li>受取時間に無理がないか確認してください。</li><li>品切れ商品がテイクアウト画面に残っていないか確認してください。</li><li>受け渡し済みの注文は完了にしてください。</li><li>連絡先が必要な場合は、店舗の個人情報管理ルールに従って扱ってください。</li></ul><h2 id="誤会計の取消-pos-レジで会計した場合、2026-04-21-phase-4d-5c-bb-c" tabindex="-1">誤会計の取消（POS レジで会計した場合、2026-04-21 Phase 4d-5c-bb-C） <a class="header-anchor" href="#誤会計の取消-pos-レジで会計した場合、2026-04-21-phase-4d-5c-bb-c" aria-label="Permalink to &quot;誤会計の取消（POS レジで会計した場合、2026-04-21 Phase 4d-5c-bb-C）&quot;">​</a></h2><p>POS レジで <strong>ゲートウェイを経由しないで会計したテイクアウト</strong>（現金 / 手動 card / 手動 qr）を、後から管理者が論理取消できます。取引ジャーナルに「会計取消」ボタンが表示されます。</p><p><strong>取消可能条件</strong>:</p><ul><li>注文が <code>status=&#39;paid&#39;</code> になっている（POS レジで会計済み）</li><li>支払方法が現金 / 手動 card / 手動 qr（ゲートウェイ非経由）</li><li>分割会計ではない</li><li>まだ返金・取消していない</li></ul><p><strong>取消できないもの（本機能では）</strong>:</p><ul><li>オンライン（Stripe）で決済したテイクアウト → 本機能ではなく<strong>返金（refund）経路</strong>で処理（下記「オンライン決済テイクアウトの返金」を参照）</li><li>分割会計 / 返金済み / 既に取消済み</li></ul><p>操作場所と動作は POS レジ章「通常会計も取り消せます」を参照。現金会計の取消は <code>cash_log</code> に相殺行が入りレジ残高は合いますが、お客さんに現金を返す場合は手渡しで別途対応してください。</p><h2 id="オンライン決済テイクアウトの返金-2026-04-21-phase-4d-5c-bb-d" tabindex="-1">オンライン決済テイクアウトの返金（2026-04-21 Phase 4d-5c-bb-D） <a class="header-anchor" href="#オンライン決済テイクアウトの返金-2026-04-21-phase-4d-5c-bb-d" aria-label="Permalink to &quot;オンライン決済テイクアウトの返金（2026-04-21 Phase 4d-5c-bb-D）&quot;">​</a></h2><p>Stripe オンライン決済したテイクアウト注文の誤会計は、<strong>返金（refund）</strong> で処理します。「会計取消」ではなく既存の「返金」機能を使います。</p><h3 id="実証済みの範囲" tabindex="-1">実証済みの範囲 <a class="header-anchor" href="#実証済みの範囲" aria-label="Permalink to &quot;実証済みの範囲&quot;">​</a></h3><ul><li><strong>Stripe Connect Checkout で決済したテイクアウト</strong>（POSLA のテナント口座に transfer される通常形態）で、お客様がクレジットカードで決済したケース</li><li>操作は POSLA 運営にご相談ください（テナント画面からの直接操作はまだ一般化していません）</li><li>返金するとお客様のカードに全額戻り、POSLA に渡っていた手数料も同時に戻します（canonical な destination charges refund）</li></ul><h3 id="まだ一般化していない範囲-別対応-要確認" tabindex="-1">まだ一般化していない範囲（別対応 / 要確認） <a class="header-anchor" href="#まだ一般化していない範囲-別対応-要確認" aria-label="Permalink to &quot;まだ一般化していない範囲（別対応 / 要確認）&quot;">​</a></h3><ul><li>店頭 POS レジの Stripe Terminal で決済したテイクアウト（実データ 0 件のため運用検証未実施）</li><li>Stripe Direct 接続（テナントが自前で Stripe API key を設定している方式）のテイクアウト（ほぼ非運用）</li><li>オンライン決済の「一部だけ返金」（部分返金 / partial refund）</li><li>オンライン決済テイクアウトに「会計取消（void）」を使うこと（本機能は返金の責務、取消の責務は別）</li></ul><p>これらが必要になった場合は、運用上 POSLA 運営に相談してください。技術的には追加実装・追加検証が必要です。</p><h3 id="実行後のお客様への影響" tabindex="-1">実行後のお客様への影響 <a class="header-anchor" href="#実行後のお客様への影響" aria-label="Permalink to &quot;実行後のお客様への影響&quot;">​</a></h3><ul><li>Stripe 側で返金処理が実行されると、お客様のカード明細に返金が反映されます（通常 5〜10 営業日）</li><li>テナント側の売上レポートには「返金済」として表示され、実売上からは自動除外されます</li><li>注文自体の状態（調理・受取のステータス）は、返金しても自動では変わりません。必要に応じてテイクアウト管理画面で個別対応してください</li></ul><h2 id="お客様画面でのエラー表示-2026-04-21-phase-4d-5c-bb-f" tabindex="-1">お客様画面でのエラー表示（2026-04-21 Phase 4d-5c-bb-F） <a class="header-anchor" href="#お客様画面でのエラー表示-2026-04-21-phase-4d-5c-bb-f" aria-label="Permalink to &quot;お客様画面でのエラー表示（2026-04-21 Phase 4d-5c-bb-F）&quot;">​</a></h2><p>Stripe 決済が完了したのに、POSLA 側で注文の記録に失敗したごく稀なケースでは、お客様の画面に次のメッセージが表示されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>決済確認に失敗しました</span></span>
<span class="line"><span>決済は Stripe 側で完了している可能性があります。</span></span>
<span class="line"><span>お手数ですが、下記の注文番号を添えて店舗まで直接お問い合わせください。</span></span>
<span class="line"><span>注文番号: XXXXXXXX</span></span></code></pre></div><p>この場合、店舗（運営）側では次の手順で確認してください。</p><ol><li>POSLA 運営に連絡してエラーログ（<code>php_errors.log</code> の <code>[4d-5c-bb-F][takeout-payment] persistence_failed</code> 行）の調査を依頼</li><li>order_id と Stripe PaymentIntent ID を取得</li><li>Stripe ダッシュボード上で PaymentIntent の decision 成否を確認</li><li>必要に応じて手動で注文記録を作成、または Stripe 側で返金してお客様に連絡</li></ol><p>※ キャンセル表示（オレンジ「決済がキャンセルされました」）とは別の表示です。お客様がキャンセル操作をした場合はキャンセル画面、決済完了しているのに記録失敗した場合は上記のエラー画面になります。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>注文が入らない</td><td>テイクアウトが有効か、受付時間内か確認してください。</td></tr><tr><td>受取時間が選べない</td><td>受付時間、準備時間、注文上限を確認してください。</td></tr><tr><td>決済が完了しない</td><td>決済設定とお客様の入力状況を確認してください。</td></tr><tr><td>お客様画面に「決済確認に失敗しました」と表示される</td><td>上記「お客様画面でのエラー表示」を参照。POSLA 運営に調査依頼してください。</td></tr><tr><td>注文を停止したい</td><td>テイクアウト設定を無効にし、案内QRの掲示も確認してください。</td></tr></tbody></table>`,32)])])}const u=t(r,[["render",n]]);export{b as __pageData,u as default};
